module top_module(
    input CLK,
    input D,
    input SET,
    input CLR,
    output reg Q,
    output reg Q_bar
);always @(posedge CLK, posedge SET, posedge CLR) begin
  wire _tap_CLK = CLK & {1{1'b1}};

    if (SET) begin
        Q <= 1'b1;
        Q_bar <= 1'b0;
    end else if (CLR) begin
        Q <= 1'b0;
        Q_bar <= 1'b1;
    end else begin
        Q <= D;
        Q_bar <= ~D;
    end
end

endmodule
